public static boolean isValid(String bodyHtml, Whitelist whitelist) {
    Document dirtyDocument = parseBodyFragment(bodyHtml, "");
    return new Cleaner(whitelist).isValid(dirtyDocument);
}

public static List<Node> parseFragment(String fragmentHtml, Element context, String baseUri) {
    HtmlTreeBuilder treeBuilder = new HtmlTreeBuilder();
    return treeBuilder.parseFragment(fragmentHtml, context, baseUri, ParseErrorList.noTracking(), treeBuilder.defaultSettings());
}

public boolean isValid(Document dirtyDocument) {
    Validate.notNull(dirtyDocument);

    Document clean = Document.createShell(dirtyDocument.baseUri());
    int numDiscarded = copySafeNodes(dirtyDocument.body(), clean.body());
    return numDiscarded == 0 && clean.body().children().size() == dirtyDocument.body().children().size();
}

