@Test public void testIsValidWithEmptyInput() {
    String empty = "";
    assertTrue(Jsoup.isValid(empty, Whitelist.basic()));
    assertTrue(Jsoup.isValid(empty, Whitelist.none()));
}

@Test public void testIsValidWithWhitespaceOnly() {
    String whitespace = "   \n\t  ";
    assertTrue(Jsoup.isValid(whitespace, Whitelist.basic()));
    assertTrue(Jsoup.isValid(whitespace, Whitelist.none()));
}

@Test public void testIsValidWithPlainText() {
    String plainText = "Just plain text without any tags";
    assertTrue(Jsoup.isValid(plainText, Whitelist.basic()));
    assertTrue(Jsoup.isValid(plainText, Whitelist.none()));
}

@Test public void testIsValidWithNestedAllowedTags() {
    String nested = "<p><b><i>Nested allowed tags</i></b></p>";
    assertTrue(Jsoup.isValid(nested, Whitelist.basic()));
    assertFalse(Jsoup.isValid(nested, Whitelist.none()));
}

@Test public void testIsValidWithMultipleTopLevelElements() {
    String multiple = "<p>First</p><p>Second</p><div>Third</div>";
    assertFalse(Jsoup.isValid(multiple, Whitelist.basic()));
}

@Test public void testIsValidWithDisallowedAttribute() {
    String disallowedAttr = "<p id='test'>Text</p>";
    assertFalse(Jsoup.isValid(disallowedAttr, Whitelist.basic()));
}

@Test public void testIsValidDocumentWithEmptyBody() {
    String emptyBody = "<html><head></head><body></body></html>";
    Whitelist relaxed = Whitelist.relaxed();
    Cleaner cleaner = new Cleaner(relaxed);
    Document doc = Jsoup.parse(emptyBody);
    assertTrue(cleaner.isValid(doc));
}
